       UNITY_LINK_URL = #{unityLinkUrl}, UNITY_LINK_DC = #{unityLinkDc},
       LAST_UPDT_PNTTM = CURRENT_TIMESTAMP, LAST_UPDUSR_ID = #{lastUpdusrId}
WHERE UNITY_LINK_ID = #{unityLinkId}
